<#
  deploy-perf-fonts.ps1
  Mobile performance fixes for Aetas Wealth (PageSpeed).

  WHAT IT DOES
    1. Writes assets/fonts/dancing-script-700.woff2 (self-hosted, subset ~16KB).
    2. Removes ALL render-blocking Google Fonts <link> tags sitewide
       (Dancing Script + a couple stray Open Sans links + the preconnects).
    3. Adds a local @font-face for Dancing Script into the strapline style block,
       so "wellbeing" renders identically with no third-party request.
    4. Versions main.js -> main-v5.js (so JS can be cached immutably yet still
       update for returning visitors) and rewrites references sitewide.
    5. _headers: /*.css and /*.js -> max-age=31536000, immutable.
    6. git add / commit / push.

  Idempotent. RUN FROM THE REPO ROOT:
    git pull
    .\deploy-perf-fonts.ps1
#>

$ErrorActionPreference = 'Stop'
Set-Location $PSScriptRoot
$utf8 = New-Object System.Text.UTF8Encoding($false)

Write-Host "== Aetas Wealth :: performance (self-host font + cache) ==" -ForegroundColor Cyan

# 1. Font file (embedded base64) -------------------------------------------
$fontB64 = @'

'@
New-Item -ItemType Directory -Force -Path 'assets\fonts' | Out-Null
[System.IO.File]::WriteAllBytes((Join-Path $PSScriptRoot 'assets\fonts\dancing-script-700.woff2'), [Convert]::FromBase64String($fontB64))
Write-Host "  [font] assets/fonts/dancing-script-700.woff2 written" -ForegroundColor Green

# 2-4. HTML edits sitewide -------------------------------------------------
$gfPattern = '\s*<link[^>]*fonts\.(?:googleapis|gstatic)\.com[^>]*>'
$strapTag  = '<style id="aetas-strap-style">'
$face      = "@font-face{font-family:'Dancing Script';font-style:normal;font-weight:700;font-display:swap;src:url('/assets/fonts/dancing-script-700.woff2') format('woff2')}"
$jsPattern = '(assets/js/)main\.js'

$files = Get-ChildItem -Path $PSScriptRoot -Recurse -Filter *.html | Where-Object { $_.FullName -notmatch '\\node_modules\\' }
$gfRemoved = 0; $facesAdded = 0; $jsUpdated = 0
foreach ($f in $files) {
  $c = [System.IO.File]::ReadAllText($f.FullName)
  $orig = $c
  $gfRemoved += ([regex]::Matches($c, $gfPattern)).Count
  $c = [regex]::Replace($c, $gfPattern, '')
  if ($c.Contains($strapTag) -and -not $c.Contains('dancing-script-700.woff2')) {
    $c = $c.Replace($strapTag, $strapTag + $face)
    $facesAdded++
  }
  $before = $c
  $c = [regex]::Replace($c, $jsPattern, '${1}main-v5.js')
  if ($c -ne $before) { $jsUpdated++ }
  if ($c -ne $orig) { [System.IO.File]::WriteAllText($f.FullName, $c, $utf8) }
}
Write-Host ("  [html] removed {0} google-font link(s); +@font-face on {1} page(s); versioned js on {2} page(s)" -f $gfRemoved,$facesAdded,$jsUpdated) -ForegroundColor Green

# 5. Rename main.js -> main-v5.js ------------------------------------------
$oldJs = Join-Path $PSScriptRoot 'assets\js\main.js'
if (Test-Path $oldJs) {
  git mv 'assets/js/main.js' 'assets/js/main-v5.js' 2>$null
  if (Test-Path $oldJs) { Move-Item -Force $oldJs (Join-Path $PSScriptRoot 'assets\js\main-v5.js') }
  Write-Host "  [js]   assets/js/main.js -> main-v5.js" -ForegroundColor Green
} else {
  Write-Host "  [js]   main-v5.js already in place" -ForegroundColor DarkGray
}

# 6. _headers cache policy -------------------------------------------------
$hp = Join-Path $PSScriptRoot '_headers'
$h  = [System.IO.File]::ReadAllText($hp)
$h  = $h.Replace("/*.css`n  Cache-Control: public, max-age=3600", "/*.css`n  Cache-Control: public, max-age=31536000, immutable")
$h  = $h.Replace("/*.js`n  Cache-Control: public, max-age=3600",  "/*.js`n  Cache-Control: public, max-age=31536000, immutable")
[System.IO.File]::WriteAllText($hp, $h, $utf8)
Write-Host "  [hdr]  /*.css and /*.js -> 1-year immutable" -ForegroundColor Green

# 7. git -------------------------------------------------------------------
Write-Host "== git ==" -ForegroundColor Cyan
git add -A
git commit -m "Perf: self-host Dancing Script (de-block Google Fonts), version JS, 1-year immutable CSS/JS cache"
git push
Write-Host "== done ==" -ForegroundColor Cyan
